// Parse incoming webhook payload and detect language (EN vs ES)
try {
  const startTime = Date.now();
  const body = $input.first().json;
  let customer_message = '';
  let conversation_id = '';
  if (body.customer_message) {
    customer_message = body.customer_message;
    conversation_id = body.conversation_id || '';
  } else if (body.data && body.data.item) {
    const item = body.data.item;
    conversation_id = item.id || '';
    const parts = item.conversation_parts || [];
    if (parts.length > 0) {
      customer_message = parts[parts.length - 1].body || '';
    }
    if (!customer_message && item.conversation_message) {
      customer_message = item.conversation_message.body || '';
    }
  } else if (body.message) {
    customer_message = body.message;
  } else if (body.query) {
    customer_message = body.query;
  }
  if (!customer_message) {
    throw new Error('No customer message found in payload');
  }
  customer_message = customer_message.replace(/<[^>]*>/g, '').trim();
  const spanishWords = ['necesito','tengo','caldera','v\u00e1lvula','presi\u00f3n','junta','tapita','inspecci\u00f3n','tienen','pulgadas','urgente','frio','fr\u00edo','calienta','puedo','hacer','qu\u00e9','c\u00f3mo','para','hola','buenos','d\u00edas','inventario','una','del','los','las','est\u00e1'];
  const lowerMsg = customer_message.toLowerCase();
  const spanishHits = spanishWords.filter(w => lowerMsg.includes(w)).length;
  const hasAccents = /[\u00e1\u00e9\u00ed\u00f3\u00fa\u00f1\u00bf\u00a1\u00fc]/.test(customer_message);
  const language = (spanishHits >= 2 || (spanishHits >= 1 && hasAccents)) ? 'es' : 'en';
  return [{ json: { customer_message, language, start_time: startTime, conversation_id } }];
} catch (error) {
  return [{ json: { customer_message: JSON.stringify($input.first().json), language: 'en', start_time: Date.now(), conversation_id: '', parse_error: error.message } }];
}

// Analyze vector store results for confidence threshold
// Escalate if < 2 results OR top similarity < 0.7
try {
  const items = $input.all();
  const parseData = $('Parse Input').first().json;
  const resultCount = items.length;
  const results = [];
  for (let i = 0; i < items.length; i++) {
    const item = items[i].json;
    let content = '';
    let metadata = {};
    let score = 0;
    if (item.document) {
      content = item.document.pageContent || '';
      metadata = item.document.metadata || {};
    } else {
      content = item.pageContent || item.content || item.text || '';
      metadata = item.metadata || {};
    }
    score = item.score || item.similarity || 0;
    results.push({ content, metadata, score, rank: i });
  }
  const hasEnoughResults = resultCount >= 2;
  const topScore = results.length > 0 ? results[0].score : 0;
  const hasGoodSimilarity = topScore === 0 || topScore >= 0.7;
  const confident = hasEnoughResults && hasGoodSimilarity;
  return [{ json: { confident, result_count: resultCount, top_score: topScore, results, customer_message: parseData.customer_message, language: parseData.language, start_time: parseData.start_time, conversation_id: parseData.conversation_id } }];
} catch (error) {
  const parseData = $('Parse Input').first().json;
  return [{ json: { confident: false, result_count: 0, top_score: 0, results: [], customer_message: parseData.customer_message || '', language: parseData.language || 'en', start_time: parseData.start_time || Date.now(), conversation_id: parseData.conversation_id || '', confidence_error: error.message } }];
}

// Build context and Anthropic API request body for Claude synthesis
try {
  const data = $input.first().json;
  const results = data.results || [];
  const language = data.language;
  const customer_message = data.customer_message;
  const contextParts = [];
  const skuRefs = [];
  for (let i = 0; i < results.length; i++) {
    const r = results[i];
    const content = r.content || '';
    const skuMatches = content.match(/SKU:\s*(oswald-[a-z0-9.\-]+)/gi);
    if (skuMatches) {
      for (let j = 0; j < skuMatches.length; j++) {
        const sku = skuMatches[j].replace(/SKU:\s*/i, '');
        if (!skuRefs.includes(sku)) { skuRefs.push(sku); }
      }
    }
    contextParts.push('[Result ' + (i + 1) + ']\n' + content);
  }
  const contextString = contextParts.join('\n\n');
  const langLabel = language === 'es' ? 'Spanish' : 'English';
  const systemPrompt = 'You are the product knowledge assistant for H.C. Oswald Supply Co., a boiler parts wholesaler at 725 Whittier St, Bronx NY, founded 1923. You have 103 years of institutional knowledge about heating system parts.\n\nRULES:\n1. Answer ONLY from the provided context. Do not invent part numbers or prices.\n2. Include: part name, SKU if available, price, substitution option if primary part is unavailable.\n3. If the part is not in context, say: We may not carry this. Please call 718-620-1400 during business hours (Mon-Fri 7:30AM-5PM).\n4. Answer in the SAME LANGUAGE as the customer query (' + langLabel + ').\n5. Be concise. This is a chat message.\n6. For discontinued parts, mention substitution options from context.\n7. Include price ranges when available.\n8. If the customer describes an emergency, acknowledge urgency and suggest relevant parts from context.';
  const userMessage = 'Context:\n' + contextString + '\n\nCustomer query: ' + customer_message;
  const anthropicBody = JSON.stringify({ model: 'claude-3-5-haiku-20241022', max_tokens: 400, system: systemPrompt, messages: [{ role: 'user', content: userMessage }] });
  return [{ json: { anthropic_body: anthropicBody, sku_references: skuRefs, result_count: data.result_count, top_score: data.top_score, language: data.language, start_time: data.start_time, customer_message: data.customer_message, conversation_id: data.conversation_id } }];
} catch (error) {
  const fallbackBody = JSON.stringify({ model: 'claude-3-5-haiku-20241022', max_tokens: 400, system: 'You are a helpful boiler parts assistant.', messages: [{ role: 'user', content: 'An error occurred building context. Please apologize and suggest calling 718-620-1400.' }] });
  return [{ json: { anthropic_body: fallbackBody, sku_references: [], result_count: 0, top_score: 0, language: 'en', start_time: Date.now(), customer_message: '', conversation_id: '', build_error: error.message } }];
}

// Format the success response from Claude's answer
try {
  const promptData = $('Build Prompt').first().json;
  const claudeRes = $input.first().json;
  let answer = '';
  if (claudeRes.content && Array.isArray(claudeRes.content) && claudeRes.content.length > 0) {
    answer = claudeRes.content[0].text || '';
  } else if (claudeRes.text) {
    answer = claudeRes.text;
  } else {
    answer = JSON.stringify(claudeRes);
  }
  const latency_ms = Date.now() - promptData.start_time;
  let confidence_score = 0;
  const rc = promptData.result_count || 0;
  if (rc >= 4) { confidence_score = 0.95; }
  else if (rc >= 3) { confidence_score = 0.85; }
  else if (rc >= 2) { confidence_score = 0.75; }
  else { confidence_score = 0.6; }
  if (promptData.top_score > 0 && promptData.top_score < confidence_score) {
    confidence_score = promptData.top_score;
  }
  return [{ json: { answer, sku_references: promptData.sku_references || [], confidence_score: Math.round(confidence_score * 100) / 100, language_detected: promptData.language, latency_ms } }];
} catch (error) {
  return [{ json: { answer: 'An error occurred. Please call 718-620-1400.', sku_references: [], confidence_score: 0, language_detected: 'en', latency_ms: 0, format_error: error.message } }];
}

// Format escalation response for low-confidence queries
try {
  const data = $input.first().json;
  const language = data.language || 'en';
  const latency_ms = Date.now() - (data.start_time || Date.now());
  const fallback_en = 'Let me connect you with our team. For immediate help, call 718-620-1400 (Mon-Fri 7:30AM-5PM).';
  const fallback_es = 'Perm\u00edtame conectarlo con nuestro equipo. Para ayuda inmediata, llame al 718-620-1400 (Lun-Vie 7:30AM-5PM).';
  return [{ json: { escalate: true, reason: 'low_confidence', fallback_message: language === 'es' ? fallback_es : fallback_en, language_detected: language, latency_ms } }];
} catch (error) {
  return [{ json: { escalate: true, reason: 'error', fallback_message: 'Let me connect you with our team. Call 718-620-1400.', language_detected: 'en', latency_ms: 0 } }];
}

